const text = $input.first().json.message.text;
const match = text.replace(/\/diagnostico\s*/i, '').trim();
const cnpj = match.replace(/[^\d]/g, '');

if (cnpj.length !== 14) {
  return [{ json: { erro: true, mensagem: `❌ CNPJ invalido: ${match} (${cnpj.length} digitos).\n\nUso correto:\n/diagnostico 12345678000190\n/diagnostico 12.345.678/0001-90`, chat_id: $input.first().json.message.chat.id } }];
}

const fmt = `${cnpj.slice(0,2)}.${cnpj.slice(2,5)}.${cnpj.slice(5,8)}/${cnpj.slice(8,12)}-${cnpj.slice(12)}`;

return [{ json: {
  erro: false,
  cnpj: cnpj,
  cnpj_formatado: fmt,
  chat_id: $input.first().json.message.chat.id,
  user_name: $input.first().json.message.from.first_name || 'Auditor'
} }];

// Normalizar dados de qualquer API
let data;
try {
  const b = $('6a. BrasilAPI').first().json;
  if (b && b.razao_social && !b.message) {
    data = {
      cnpj: b.cnpj, razao_social: b.razao_social,
      nome_fantasia: b.nome_fantasia || '',
      situacao: b.descricao_situacao_cadastral || 'ATIVA',
      data_inicio: b.data_inicio_atividade || '',
      cnae: String(b.cnae_fiscal || ''),
      cnae_desc: b.cnae_fiscal_descricao || '',
      natureza: b.descricao_natureza_juridica || '',
      porte: b.descricao_porte || 'DEMAIS',
      capital: Number(b.capital_social) || 0,
      simples: b.opcao_pelo_simples || false,
      mei: b.opcao_pelo_mei || false,
      uf: b.uf || '', municipio: b.municipio || '',
      telefone: b.ddd_telefone_1 || '',
      email: (b.email || '').toLowerCase(),
      qsa: (b.qsa || []).slice(0,5).map(s => ({nome: s.nome_socio||'', qual: s.qualificacao_socio||''})),
      fonte: 'BrasilAPI'
    };
  }
} catch(e) {}
if (!data) {
  try {
    const r = $('6b. ReceitaWS (Fallback)').first().json;
    if (r && r.nome) {
      const act = (r.atividade_principal||[{}])[0];
      data = {
        cnpj: (r.cnpj||'').replace(/\D/g,''), razao_social: r.nome,
        nome_fantasia: r.fantasia||'',
        situacao: r.situacao||'ATIVA',
        data_inicio: r.abertura||'',
        cnae: (act.code||'').replace(/[-.]/g,''),
        cnae_desc: act.text||'',
        natureza: r.natureza_juridica||'',
        porte: r.porte||'DEMAIS',
        capital: parseFloat((r.capital_social||'0').replace(/\./g,'').replace(',','.'))||0,
        simples: r.simples?.optante||false,
        mei: r.simei?.optante||false,
        uf: r.uf||'', municipio: r.municipio||'',
        telefone: r.telefone||'',
        email: (r.email||'').toLowerCase(),
        qsa: (r.qsa||[]).slice(0,5).map(s => ({nome: s.nome||'', qual: s.qual||''})),
        fonte: 'ReceitaWS'
      };
    }
  } catch(e) {}
}
if (!data) return [{json:{erro:true, mensagem:'APIs indisponiveis. Tente em 1 minuto.', chat_id: $('3. Extrair CNPJ').first().json.chat_id}}];
data.erro = false;
data.chat_id = $('3. Extrair CNPJ').first().json.chat_id;
return [{json: data}];

const d = $input.first().json;
if (d.erro) return [{json:d}];

const alertas = [];
const servicos = [];
const p = String(d.porte||'').toUpperCase();
let porte = 'MEDIO';
if (p.includes('MICRO')||p.includes('ME')) porte='ME';
else if (p.includes('PEQUENO')||p.includes('EPP')) porte='EPP';
else if (p.includes('GRANDE')) porte='GRANDE';

let anos=0;
if (d.data_inicio) {
  try {
    const parts = d.data_inicio.includes('/') ? d.data_inicio.split('/').reverse().join('-') : d.data_inicio;
    anos = Math.floor((Date.now() - new Date(parts).getTime())/(365.25*24*60*60*1000));
  } catch(e){}
}

const cnae2 = String(d.cnae).slice(0,2);
const capital = Number(d.capital)||0;
const fmtR = v => 'R$ '+v.toLocaleString('pt-BR',{minimumFractionDigits:2});

// === REGRAS DE DIAGNOSTICO ===
if (d.situacao && !d.situacao.toUpperCase().includes('ATIVA')) {
  alertas.push({e:'🔴',u:'URGENTE',t:`Situacao: ${d.situacao}. Risco de multas.`});
  servicos.push({desc:'Consultoria Permanente',val:porte==='ME'?1750:porte==='EPP'?3000:5250,per:'mensal',fund:'NBC PP 01'});
}
if (d.simples && capital > 500000) {
  alertas.push({e:'🔴',u:'ALTA',t:`Simples + capital ${fmtR(capital)}. Risco desenquadramento.`});
  servicos.push({desc:'Planejamento Tributario',val:porte==='ME'?2250:porte==='EPP'?3750:6000,per:'pontual',fund:'CTN, RIR/2018'});
}
if (!isNaN(cnae2) && cnae2>=10 && cnae2<=33) {
  alertas.push({e:'🟡',u:'MEDIA',t:`CNAE industrial (${d.cnae_desc}). ICMS/IPI complexo.`});
  servicos.push({desc:'Revisao SPED Fiscal',val:porte==='ME'?1750:porte==='EPP'?3000:4500,per:'pontual',fund:'Conv. ICMS'});
}
if (cnae2==='47') {
  alertas.push({e:'🟡',u:'MEDIA',t:'Comercio varejista. ICMS-ST, risco de creditos.'});
  servicos.push({desc:'Revisao SPED Fiscal',val:porte==='ME'?1750:porte==='EPP'?3000:4500,per:'pontual',fund:'Conv. ICMS'});
}
if (porte==='GRANDE' || capital>50000000) {
  alertas.push({e:'🔴',u:'ALTA',t:'Grande porte. Obrigatoriedade de auditoria (Lei 11.638/07).'});
  servicos.push({desc:'Auditoria Independente',val:porte==='GRANDE'?14000:7500,per:'mensal',fund:'NBC TA 200-720'});
}
if (capital>1000000 && (d.natureza||'').toUpperCase().includes('LTDA')) {
  alertas.push({e:'🟡',u:'MEDIA',t:`Capital ${fmtR(capital)} p/ LTDA. Avaliar auditoria.`});
  if (!servicos.find(s=>s.desc.includes('Auditoria'))) servicos.push({desc:'Auditoria Independente',val:7500,per:'mensal',fund:'NBC TA 200-720'});
}
if (anos > 5) {
  alertas.push({e:'🟡',u:'MEDIA',t:`${anos} anos de operacao sem revisao independente.`});
  if (!servicos.find(s=>s.desc.includes('ECD'))) servicos.push({desc:'Revisao SPED ECD',val:porte==='ME'?1500:porte==='EPP'?2250:3750,per:'pontual',fund:'IN RFB 1774'});
}
if (!alertas.length) {
  alertas.push({e:'🟢',u:'NORMAL',t:'Nenhuma irregularidade na analise preliminar.'});
  servicos.push({desc:'Revisao SPED ECD',val:3750,per:'pontual',fund:'IN RFB 1774'});
}

const total = servicos.reduce((s,x)=>s+x.val,0);

// Socio administrador
let contato = 'Prezado(a) Responsavel';
for (const s of (d.qsa||[])) {
  if ((s.qual||'').toLowerCase().includes('admin')) { contato=s.nome; break; }
}
if (contato==='Prezado(a) Responsavel' && d.qsa?.length) contato=d.qsa[0].nome;

const regime = d.mei ? 'MEI' : d.simples ? 'Simples Nacional' : 'Lucro Presumido/Real';
const cnpjFmt = $('3. Extrair CNPJ').first().json.cnpj_formatado;

// === MENSAGEM TELEGRAM ===
let msg = `✅ <b>DIAGNOSTICO - ${d.razao_social}</b>\n`;
msg += '━━━━━━━━━━━━━━━━━━━━━━━━\n';
if (d.nome_fantasia) msg += `🏷️ ${d.nome_fantasia}\n`;
msg += `📋 CNPJ: ${cnpjFmt}\n`;
msg += `📍 ${d.municipio}/${d.uf} | ${porte}\n`;
msg += `💼 ${d.cnae_desc}\n`;
msg += `📊 ${regime}\n`;
if (capital>0) msg += `💰 Capital: ${fmtR(capital)}\n`;
msg += `👥 Socios: ${(d.qsa||[]).length}\n`;
msg += `📅 Ativa ha ${anos} anos\n`;
msg += '\n⚠️ <b>PONTOS DE ATENCAO:</b>\n';
alertas.forEach((a,i) => msg += `${a.e} ${i+1}. ${a.t}\n`);
msg += '\n💼 <b>SERVICOS RECOMENDADOS:</b>\n';
servicos.forEach(s => {
  const per = s.per==='mensal' ? '/mes' : ' (pontual)';
  msg += `  • ${s.desc}: <b>${fmtR(s.val)}</b>${per}\n`;
  msg += `    <i>(${s.fund})</i>\n`;
});
msg += `\n💰 <b>Total: ${fmtR(total)}</b>\n`;
msg += `\n👤 Contato: ${contato.split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1).toLowerCase()).join(' ')}`;

return [{json:{
  erro: false,
  telegram_msg: msg,
  dados: d,
  alertas, servicos, total,
  total_fmt: fmtR(total),
  contato: contato.split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1).toLowerCase()).join(' '),
  porte, regime,
  email_prospect: d.email || '',
  chat_id: d.chat_id,
  cnpj_formatado: cnpjFmt
}}];

// Gerar HTML da proposta comercial usando template AUDIPER
const diag = $('8. Gerar Diagnostico').first().json;
const d = diag.dados;
const hoje = new Date();
const dataFmt = `${String(hoje.getDate()).padStart(2,'0')}/${String(hoje.getMonth()+1).padStart(2,'0')}/${hoje.getFullYear()}`;
const ref = `PROP-${hoje.getFullYear()}-${String(hoje.getMonth()+1).padStart(2,'0')}${String(hoje.getDate()).padStart(2,'0')}`;
const fmtR = v => 'R$ '+v.toLocaleString('pt-BR',{minimumFractionDigits:2});

// Pontos de atencao HTML
let pontosHTML = '';
diag.alertas.forEach(a => {
  const cor = a.u==='URGENTE'?'#dc2626':a.u==='ALTA'?'#ea580c':a.u==='MEDIA'?'#d97706':'#059669';
  pontosHTML += `<tr><td width="28" style="vertical-align:top;padding:4px 0;"><span style="color:${cor};font-size:16px;">${a.e}</span></td><td style="padding:4px 0;font-size:11px;color:#78350f;line-height:1.6;"><strong>[${a.u}]</strong> ${a.t}</td></tr>`;
});

// Servicos detalhados HTML
let servicosHTML = '';
diag.servicos.forEach(s => {
  servicosHTML += `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #e2e8f0;border-left:4px solid #1a5276;border-radius:0 8px 8px 0;overflow:hidden;margin-bottom:14px;"><tr style="background:#f8fafc;"><td style="padding:14px 18px;"><p style="margin:0 0 6px 0;font-size:12px;font-weight:700;color:#1a5276;">${s.desc}</p><p style="margin:0 0 6px 0;font-size:11px;color:#334155;line-height:1.6;">Servico de ${s.desc.toLowerCase()} aplicado a empresa ${d.razao_social}, conforme normas vigentes.</p><p style="margin:0;font-size:10px;color:#64748b;font-style:italic;">Fundamentacao: ${s.fund}</p></td></tr></table>`;
});

// Tabela resumo
let tabelaHTML = '';
diag.servicos.forEach((s,i) => {
  const bg = i%2===0 ? '#fff' : '#f8fafc';
  const per = s.per==='mensal' ? 'Mensal' : 'Pontual';
  tabelaHTML += `<tr style="background:${bg};"><td style="padding:10px 14px;font-size:11px;border-bottom:1px solid #e2e8f0;">${s.desc}</td><td style="padding:10px 14px;font-size:11px;text-align:center;border-bottom:1px solid #e2e8f0;">${per}</td><td style="padding:10px 14px;font-size:11px;text-align:right;font-weight:600;color:#1a5276;border-bottom:1px solid #e2e8f0;">${fmtR(s.val)}</td></tr>`;
});

// Email do prospect
const emailProspect = d.email || '';
const assunto = `Proposta de Servicos Profissionais - AUDIPER | ${d.razao_social}`;

return [{json:{
  ref_proposta: ref,
  data_proposta: dataFmt,
  assunto_email: assunto,
  email_prospect: emailProspect,
  contato: diag.contato,
  razao_social: d.razao_social,
  cnpj_formatado: diag.cnpj_formatado,
  porte: diag.porte,
  regime: diag.regime,
  municipio: d.municipio,
  uf: d.uf,
  cnae: d.cnae,
  cnae_desc: d.cnae_desc,
  pontos_html: pontosHTML,
  servicos_html: servicosHTML,
  tabela_html: tabelaHTML,
  total_fmt: diag.total_fmt,
  chat_id: diag.chat_id
}}];

// Pegar email da resposta do auditor ou dos dados do CNPJ
let email;
try {
  // Veio do 'Pedir Email' (caminho sem email)
  email = $('13. Pedir Email (Wait)').first().json.data?.text || '';
} catch(e) {
  // Veio direto (caminho com email)
  email = $('11. Gerar Proposta HTML').first().json.email_prospect || '';
}

// Pegar dados da proposta
let proposta;
try { proposta = $('11. Gerar Proposta HTML').first().json; } catch(e) { proposta = $input.first().json; }

email = email.trim().toLowerCase();
const valido = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

return [{json:{
  ...proposta,
  email_envio: valido ? email : '',
  email_valido: valido
}}];

